CREATE TABLE IF NOT EXISTS case_task_logs (tenant_id VARCHAR(64) NOT NULL, case_id UUID NOT NULL, task_id UUID NOT NULL, log_id UUID NOT NULL, body TEXT NOT NULL, created_by VARCHAR(255) NOT NULL, created_at BIGINT NOT NULL, PRIMARY KEY (tenant_id, case_id, task_id, log_id), FOREIGN KEY (tenant_id, case_id, task_id) REFERENCES case_tasks(tenant_id, case_id, task_id) ON DELETE CASCADE); CREATE INDEX IF NOT EXISTS idx_task_logs_tenant_task ON case_task_logs(tenant_id, case_id, task_id, created_at DESC); CREATE TABLE IF NOT EXISTS case_templates (tenant_id VARCHAR(64) NOT NULL, template_id UUID NOT NULL, name VARCHAR(255) NOT NULL, title_prefix VARCHAR(255) NOT NULL, severity INT NOT NULL DEFAULT 2, description TEXT, created_by VARCHAR(255) NOT NULL, created_at BIGINT NOT NULL, PRIMARY KEY (tenant_id, template_id)); CREATE INDEX IF NOT EXISTS idx_case_templates_tenant ON case_templates(tenant_id, name); CREATE TABLE IF NOT EXISTS case_template_tasks (tenant_id VARCHAR(64) NOT NULL, template_id UUID NOT NULL, task_id UUID NOT NULL, title TEXT NOT NULL, description TEXT, PRIMARY KEY (tenant_id, template_id, task_id), FOREIGN KEY (tenant_id, template_id) REFERENCES case_templates(tenant_id, template_id) ON DELETE CASCADE);
